<?php require __DIR__ . '/bootstrap.php'; $instanceId=(int)($_GET['instance_id']??0); if(!$instanceId) exit('Instância obrigatória.'); $auth->requireInstanceAccess($instanceId); $tx=$financial->transactions($instanceId,120); ?><!doctype html><html lang="pt-br"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Calendário</title><link rel="stylesheet" href="<?= e(base_path('assets/ui.css')) ?>"></head><body><div class="wrap"><?php financial_nav($instanceId,'calendar'); ?><div class="card"><h1 class="headline">Calendário financeiro</h1><div class="list"><?php foreach($tx as $t): ?><div class="member"><div class="meta"><strong><?= e($t['transaction_date']) ?> · <?= e($t['description']) ?></strong><span class="muted"><?= e($t['status']) ?> · <?= e($t['type']) ?></span></div><span class="tag">R$ <?= number_format((float)$t['amount'],2,',','.') ?></span></div><?php endforeach; ?></div></div></div></body></html>
